}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int SeatNumber { get; set; }
    public bool IsAvailable { get; set; }
    public virtual Event Event { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int MaxSeats { get; set; }
    public int RemainingSeats { get; set; }
    public virtual ICollection<Ticket> Tickets { get; set; }
}

public async Task BuyTicketsAsync(int eventId, int quantity)
{
    using var dbContext = new EventBookingContext();
    var @event = await dbContext.Events.FindAsync(eventId);

    if (@event == null || @event.RemainingSeats < quantity)
        throw new ArgumentException("Invalid event or insufficient seats");

    var ticketsToBuy = Enumerable.Range(1, quantity).Select(i => new Ticket { EventId = eventId, SeatNumber = @event.RemainingSeats - i + 1, IsAvailable = true });

    foreach (var ticket in ticketsToBuy)
    {
        dbContext.Entry(ticket).State = EntityState.Added;
    }

    await dbContext.SaveChangesAsync();

    @event.RemainingSeats -= quantity;
    dbContext.Entry(@event).State = EntityState.Modified;
    await dbContext.SaveChangesAsync();
}